export default function memoize(fn) {
  const root = new Map();
  return function memoized(...args) {
    let map = root;
    for (const arg of args) {
      if (!map.has(arg)) map.set(arg, new Map());
      map = map.get(arg);
    }
    if (map.has('result')) return map.get('result');
    const result = fn(...args);
    map.set('result', result);
    return result;
  };
}
